            if time.time() > trade.expires_at:
                trade.status = "expired"
                return {"success": False, "error": "Trade has expired"}

            if player_id == trade.sender_id:
                trade.sender_confirmed = True
            elif player_id == trade.receiver_id:
                trade.receiver_confirmed = True
